const items = $input.all();
const item = items[0];

const jiraId     = item.json.body?.jira_id     || item.json.jira_id     || 'NO-ID';
const author     = item.json.body?.author       || item.json.author       || 'Unknown';
const reviewer   = item.json.body?.reviewer     || item.json.reviewer     || 'Morgan Housel';
const prNumber   = item.json.body?.pr_number    || item.json.pr_number    || '';
const prTitle    = item.json.body?.pr_title     || item.json.pr_title     || '';
const prUrl      = item.json.body?.pr_url       || item.json.pr_url       || '#';
const dbFiles    = item.json.body?.db_files     || item.json.db_files     || 'No DB scripts changed';
const pageId     = item.json.body?.page_id      || item.json.page_id      || '688129';

const newRow = `<tr>
  <td><p><strong>${jiraId}</strong></p></td>
  <td><p>${author}</p></td>
  <td><p><a href="${prUrl}">Pull request ${prNumber}: ${prTitle.substring(0, 50)}</a></p></td>
  <td><p>${dbFiles}</p></td>
  <td><p>${reviewer}</p></td>
</tr>`;

item.json.new_row  = newRow;
item.json.page_id  = pageId;
item.json.jira_id  = jiraId;

return items;

const items = $input.all();
const item = items[0];

const currentVersion = item.json.version?.number || 1;
const currentBody    = item.json.body?.storage?.value || '';
const pageId         = $('Build Row').item.json.page_id || '688129';
const newRow         = $('Build Row').item.json.new_row;

let updatedBody;

if (currentBody.includes('<table>') || currentBody.includes('<table ')) {
  if (currentBody.includes('</tbody>')) {
    updatedBody = currentBody.replace('</tbody>', `${newRow}\n</tbody>`);
  } else {
    updatedBody = currentBody.replace('</table>', `${newRow}\n</table>`);
  }
} else {
  updatedBody = `
<h2>Database Changes Log</h2>
<table><tbody>
  <tr>
    <th><p><strong>User Story</strong></p></th>
    <th><p><strong>User Name</strong></p></th>
    <th><p><strong>PR</strong></p></th>
    <th><p><strong>Pkg Changes (DB Scripts)</strong></p></th>
    <th><p><strong>Reviewer</strong></p></th>
  </tr>
  ${newRow}
</tbody></table>
<p><em>Auto-generated by Agentic Documentation System</em></p>`;
}

item.json.put_body = {
  id: pageId,
  status: 'current',
  title: 'PI DB Changes - Automated Log',
  body: { representation: 'storage', value: updatedBody },
  version: { number: currentVersion + 1, message: `PR merged: ${$('Build Row').item.json.jira_id}` }
};

return items;

const items = $input.all();
const item = items[0];
item.json.final_body = JSON.stringify(item.json.put_body);
return items;
